class Solution:
    def longestCommonPrefix(self, words):
        def lcp(a, b):
            m = min(len(a), len(b))
            i = 0
            while i < m and a[i] == b[i]:
                i += 1
            return i
        n = len(words)
        if n <= 1:
            return [0] * n
        pair = [lcp(words[j], words[j+1]) for j in range(n - 1)]
        m = len(pair)
        pre = [0] * (m + 1)
        for j in range(m):
            pre[j+1] = max(pre[j], pair[j])
        suf = [0] * (m + 1)
        for j in range(m - 1, -1, -1):
            suf[j] = max(suf[j+1], pair[j])
        ans = []
        for i in range(n):
            best = 0
            # pairs entirely before index i: pair indices [0, i-2]
            if i - 1 >= 1:
                best = max(best, pre[i - 1])
            # pairs entirely after index i: pair indices [i+1, m-1]
            if i + 1 <= m - 1:
                best = max(best, suf[i + 1])
            # bridged pair (i-1, i+1)
            if 0 < i < n - 1:
                best = max(best, lcp(words[i - 1], words[i + 1]))
            ans.append(best)
        return ans

