var longestCommonPrefix = function(words) {
    const lcp = (a, b) => {
        const m = Math.min(a.length, b.length);
        let i = 0;
        while (i < m && a[i] === b[i]) i++;
        return i;
    };
    const n = words.length;
    if (n <= 1) return new Array(n).fill(0);
    const pair = [];
    for (let j = 0; j < n - 1; j++) pair.push(lcp(words[j], words[j+1]));
    const m = pair.length;
    const pre = new Array(m + 1).fill(0);
    for (let j = 0; j < m; j++) pre[j+1] = Math.max(pre[j], pair[j]);
    const suf = new Array(m + 1).fill(0);
    for (let j = m - 1; j >= 0; j--) suf[j] = Math.max(suf[j+1], pair[j]);
    const ans = [];
    for (let i = 0; i < n; i++) {
        let best = 0;
        if (i - 1 >= 1) best = Math.max(best, pre[i - 1]);
        if (i + 1 <= m - 1) best = Math.max(best, suf[i + 1]);
        if (i > 0 && i < n - 1) best = Math.max(best, lcp(words[i - 1], words[i + 1]));
        ans.push(best);
    }
    return ans;
};
